SELECT id, user_id, analysis_id, conversation_content, status, error_message, processing_time_ms,
       educational_summary, created_at, updated_at
FROM conversation_analysis
WHERE analysis_id = #{analysisId}
  AND user_id = #{userId}

SELECT id, user_id, analysis_id, conversation_content, status, error_message, processing_time_ms,
       educational_summary, created_at, updated_at
FROM conversation_analysis
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM conversation_analysis
WHERE user_id = #{userId}

SELECT id, user_id, analysis_id, conversation_content, status, error_message, processing_time_ms,
       educational_summary, created_at, updated_at
FROM conversation_analysis

    user_id = #{userId}

        AND status = #{status}


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


        AND conversation_content LIKE CONCAT('%', #{keyword}, '%')


ORDER BY created_at DESC

